<template>
  <el-dialog :before-close="closeSidebar" :visible.sync="visible" append-to-body fullscreen title="系统设置">
    <el-form :model="userSetting" label-position="top">
      <el-form-item label="本地素材文件夹路径">
        <el-input v-model.trim="userSetting.localMaterialPath" />
      </el-form-item>
    </el-form>
    <el-button @click="submitSetting" style="position: absolute; right: 20px; bottom: 20px" type="primary">确 定 </el-button>
  </el-dialog>
</template>
<script>
import { addSettingInfo, updateSettingInfo, getSettingInfo } from '@/api/main';
export default {
  name: 'SettingDialog',
  data() {
    return {
      visible: false,
      userSetting: {
        localMaterialPath: ''
      }
    };
  },
  methods: {
    handleOpen(visible) {
      this.visible = visible;
      getSettingInfo().then((response) => {
        this.userSetting = response.data || {};
      });
    },
    closeSidebar(done) {
      this.visible = false;
      this.userSetting = {};
      done && done();
    },
    async submitSetting() {
      if (this.userSetting && this.userSetting.id !== undefined && this.userSetting.id !== null) {
        await updateSettingInfo(this.userSetting);
      } else {
        await addSettingInfo(this.userSetting);
      }
      // 这里可以添加保存设置的逻辑，例如调用 API 保存用户设置
      this.$message.success('设置已保存');
      this.$emit('refreshLocalFile', null); // 通知父组件刷新用户信息
      this.closeSidebar();
    }
  }
};
</script>
<style scoped>
/deep/ .el-dialog {
  background: #000;
}

/deep/ .el-dialog__title {
  color: #fff;
}

/deep/ .el-form-item__label {
  color: #fff;
}
</style>
